-- Recipeace — reference data seed (GENERATED — do not edit by hand).
-- Source of truth: src/data/cocktail-seed.ts   ·   Regenerate: npm run generate:seed
--
-- Idempotent: upserts keyed on natural keys (ingredient name, alias, and
-- substitution pair), so it is safe to re-run. Paste into the Supabase SQL
-- Editor and run AFTER the migrations.

begin;

-- 1. Ingredients (parent_id is resolved by name in step 2).
on conflict (name) do update set
  category = excluded.category,
  is_staple = excluded.is_staple;

-- 2. Resolve the is-a hierarchy: map each child name to its parent's id.
update public.ingredients c
set parent_id = p.id
from (values
  ('bourbon', 'whiskey'),
  ('rye whiskey', 'whiskey'),
  ('scotch', 'whiskey'),
  ('islay scotch', 'scotch'),
  ('irish whiskey', 'whiskey'),
  ('london dry gin', 'gin'),
  ('old tom gin', 'gin'),
  ('plymouth gin', 'gin'),
  ('white rum', 'rum'),
  ('gold rum', 'rum'),
  ('dark rum', 'rum'),
  ('aged rum', 'rum'),
  ('spiced rum', 'rum'),
  ('overproof rum', 'rum'),
  ('blanco tequila', 'tequila'),
  ('reposado tequila', 'tequila'),
  ('añejo tequila', 'tequila'),
  ('cognac', 'brandy'),
  ('armagnac', 'brandy'),
  ('pisco', 'brandy'),
  ('apple brandy', 'brandy'),
  ('triple sec', 'orange liqueur'),
  ('cointreau', 'orange liqueur'),
  ('grand marnier', 'orange liqueur'),
  ('orange curaçao', 'orange liqueur'),
  ('blue curaçao', 'orange liqueur'),
  ('campari', 'bitter liqueur'),
  ('aperol', 'bitter liqueur'),
  ('fernet branca', 'bitter liqueur'),
  ('averna', 'bitter liqueur'),
  ('cynar', 'bitter liqueur'),
  ('green chartreuse', 'chartreuse'),
  ('yellow chartreuse', 'chartreuse'),
  ('sweet vermouth', 'vermouth'),
  ('dry vermouth', 'vermouth'),
  ('blanc vermouth', 'vermouth'),
  ('fino sherry', 'sherry'),
  ('manzanilla sherry', 'sherry'),
  ('amontillado sherry', 'sherry'),
  ('oloroso sherry', 'sherry'),
  ('pedro ximénez sherry', 'sherry'),
  ('champagne', 'sparkling wine'),
  ('prosecco', 'sparkling wine'),
  ('cava', 'sparkling wine'),
  ('angostura bitters', 'bitters'),
  ('orange bitters', 'bitters'),
  ('peychaud''s bitters', 'bitters'),
  ('chocolate bitters', 'bitters'),
  ('crushed ice', 'ice')
) as m (child, parent)
join public.ingredients p on p.name = m.parent
where c.name = m.child;

-- 3. Aliases (brand / spelling variants -> canonical ingredient).
select v.alias, i.id
from (values
  ('fresh lime juice', 'lime juice'),
  ('lime juice (fresh)', 'lime juice'),
  ('juice of 1 lime', 'lime juice'),
  ('fresh lemon juice', 'lemon juice'),
  ('juice of 1 lemon', 'lemon juice'),
  ('club soda', 'soda water'),
  ('seltzer', 'soda water'),
  ('sparkling water', 'soda water'),
  ('silver tequila', 'blanco tequila'),
  ('white tequila', 'blanco tequila'),
  ('anejo tequila', 'añejo tequila'),
  ('light rum', 'white rum'),
  ('silver rum', 'white rum'),
  ('cachaca', 'cachaça'),
  ('kahlua', 'coffee liqueur'),
  ('kahlúa', 'coffee liqueur'),
  ('tia maria', 'coffee liqueur'),
  ('baileys', 'cream liqueur'),
  ('irish cream', 'cream liqueur'),
  ('st-germain', 'elderflower liqueur'),
  ('st germain', 'elderflower liqueur'),
  ('luxardo', 'maraschino liqueur'),
  ('maraschino', 'maraschino liqueur'),
  ('midori', 'melon liqueur'),
  ('blackberry liqueur', 'crème de mûre'),
  ('creme de mure', 'crème de mûre'),
  ('blackcurrant liqueur', 'crème de cassis'),
  ('rosso vermouth', 'sweet vermouth'),
  ('red vermouth', 'sweet vermouth'),
  ('italian vermouth', 'sweet vermouth'),
  ('french vermouth', 'dry vermouth'),
  ('bianco vermouth', 'blanc vermouth'),
  ('lillet', 'lillet blanc'),
  ('pomegranate syrup', 'grenadine'),
  ('almond syrup', 'orgeat'),
  ('orgeat syrup', 'orgeat'),
  ('rich syrup', 'rich simple syrup'),
  ('simple syrup (1:1)', 'simple syrup'),
  ('angostura', 'angostura bitters'),
  ('aromatic bitters', 'angostura bitters'),
  ('peychauds', 'peychaud''s bitters'),
  ('calvados', 'apple brandy'),
  ('applejack', 'apple brandy'),
  ('scotch whisky', 'scotch'),
  ('coco lopez', 'cream of coconut'),
  ('coconut cream', 'cream of coconut'),
  ('tabasco', 'hot sauce'),
  ('worcestershire', 'worcestershire sauce'),
  ('brewed coffee', 'coffee'),
  ('egg whites', 'egg white'),
  ('champagne (brut)', 'champagne')
) as v (alias, ingredient)
join public.ingredients i on i.name = v.ingredient
on conflict (alias) do update set ingredient_id = excluded.ingredient_id;

-- 4. Substitutions ("in a pinch" swaps).
select i.id, s.id, v.note
from (values
  ('bourbon', 'rye whiskey', 'rye is spicier and drier; bourbon rounder and sweeter'),
  ('cointreau', 'triple sec', 'generic triple sec is lower proof and less complex'),
  ('cointreau', 'grand marnier', 'grand marnier is cognac-based, richer and sweeter'),
  ('campari', 'aperol', 'aperol is lighter, sweeter, lower proof'),
  ('lillet blanc', 'cocchi americano', 'cocchi is more bitter and quinine-forward'),
  ('green chartreuse', 'yellow chartreuse', 'yellow is milder, sweeter, lower proof'),
  ('cognac', 'armagnac', 'armagnac is more rustic and robust'),
  ('lemon juice', 'lime juice', 'shifts the flavor profile; not identical'),
  ('simple syrup', 'demerara syrup', 'demerara adds molasses depth and color'),
  ('simple syrup', 'honey syrup', 'honey adds floral depth'),
  ('white rum', 'gold rum', 'gold adds light barrel character'),
  ('white rum', 'cachaça', 'cachaça is grassier and funkier'),
  ('ginger beer', 'ginger ale', 'ginger ale is milder and sweeter'),
  ('tequila', 'mezcal', 'mezcal adds smoke'),
  ('maraschino cherry', 'luxardo cherry', 'luxardo are premium; maraschino brighter and sweeter'),
  ('egg white', 'aquafaba', 'vegan substitute with the same foaming'),
  ('absinthe', 'pastis', 'pastis (Herbsaint/Pernod) is sweeter and lower proof'),
  ('orange curaçao', 'triple sec', 'close enough for most builds'),
  ('scotch', 'irish whiskey', 'irish is lighter and smoother; loses peat character')
) as v (ingredient, substitute, note)
join public.ingredients i on i.name = v.ingredient
join public.ingredients s on s.name = v.substitute
on conflict (ingredient_id, substitute_id) do update set note = excluded.note;

commit;